/**
 * Intel Visibility Service
 *
 * Enforces visibility level filtering on Intel queries
 * to prevent information leakage across org/alliance boundaries.
 *
 * Phase 1 Scope: PUBLIC, ORG, PRIVATE
 * Phase 2: ALLIANCEONLY (deferred pending multi-alliance architecture)
 */

import { Repository } from 'typeorm';

import { AppDataSource } from '../../data-source';
import { IntelAuditAction, IntelAuditLog } from '../../models/IntelAuditLog';
import { IntelEntry } from '../../models/IntelEntry';
import { OrganizationMembership } from '../../models/OrganizationMembership';
import { ForbiddenError, NotFoundError } from '../../utils/apiErrors';
import { logger } from '../../utils/logger';

import { intelAuditLogger } from './IntelAuditLogger';

/**
 * Visibility level enumeration
 * Phase 1: PUBLIC, ORG, PRIVATE
 * Phase 2: ALLIANCEONLY (deferred)
 */
export enum IntelVisibilityLevel {
  PUBLIC = 'PUBLIC',
  ORG = 'ORG',
  PRIVATE = 'PRIVATE',
  // ALLIANCEONLY = 'ALLIANCEONLY', // Phase 2
}

/**
 * User role enumeration (for visibility checks)
 */
export enum UserRoleInOrg {
  ADMIN = 'admin',
  OFFICER = 'officer',
  MEMBER = 'member',
  GUEST = 'guest',
}

/**
 * Result of visibility check
 */
export interface VisibilityCheckResult {
  canView: boolean;
  reason?: string;
  visibilityLevel?: IntelVisibilityLevel;
}

/**
 * Service for enforcing Intel visibility controls
 */
export class IntelVisibilityService {
  private static instance: IntelVisibilityService;
  private readonly intelRepo: Repository<IntelEntry>;
  private readonly membershipRepo: Repository<OrganizationMembership>;
  private readonly auditLogRepo: Repository<IntelAuditLog>;

  // Simple in-memory cache for user roles (1 hour TTL)
  private userRoleCache: Map<string, { role: UserRoleInOrg; timestamp: number }> = new Map();
  private readonly ROLE_CACHE_TTL_MS = 3600000; // 1 hour

  constructor() {
    this.intelRepo = AppDataSource.getRepository(IntelEntry);
    this.membershipRepo = AppDataSource.getRepository(OrganizationMembership);
    this.auditLogRepo = AppDataSource.getRepository(IntelAuditLog);
  }

  /**
   * Singleton instance accessor
   */
  public static getInstance(): IntelVisibilityService {
    if (!IntelVisibilityService.instance) {
      IntelVisibilityService.instance = new IntelVisibilityService();
    }
    return IntelVisibilityService.instance;
  }

  /**
   * Get user role in organization (with caching)
   */
  private async getUserRoleInOrganization(
    userId: string,
    organizationId: string
  ): Promise<UserRoleInOrg> {
    const cacheKey = `${userId}:${organizationId}`;
    const cached = this.userRoleCache.get(cacheKey);

    // Return cached role if still valid (< 1 hour old)
    if (cached && Date.now() - cached.timestamp < this.ROLE_CACHE_TTL_MS) {
      return cached.role;
    }

    try {
      const membership = await this.membershipRepo.findOne({
        where: { userId, organizationId },
        relations: ['userRole'],
      });

      if (!membership) {
        return UserRoleInOrg.GUEST;
      }

      // Map userRole to internal enum (handle various role names)
      let role = UserRoleInOrg.MEMBER;
      if (membership.userRole?.name) {
        const roleName = membership.userRole.name.toLowerCase();
        if (roleName.includes('admin')) {
          role = UserRoleInOrg.ADMIN;
        } else if (roleName.includes('officer') || roleName.includes('commander')) {
          role = UserRoleInOrg.OFFICER;
        }
      }

      // Cache the role
      this.userRoleCache.set(cacheKey, { role, timestamp: Date.now() });

      return role;
    } catch (error: unknown) {
      logger.warn('Failed to get user role', { userId, organizationId, error });
      return UserRoleInOrg.GUEST;
    }
  }

  /**
   * Clear role cache (call on role change events)
   */
  clearRoleCache(userId: string, organizationId: string): void {
    const cacheKey = `${userId}:${organizationId}`;
    this.userRoleCache.delete(cacheKey);
  }

  /**
   * Check if user can view specific Intel entry
   * Returns 403 Forbidden on denial (not 404) to avoid revealing existence
   */
  async canViewIntel(
    userId: string,
    intelId: string,
    organizationId: string
  ): Promise<VisibilityCheckResult> {
    try {
      // Find intel entry (org-scoped)
      const intel = await this.intelRepo.findOne({
        where: { id: intelId, organizationId },
      });

      if (!intel) {
        // Record doesn't exist or cross-org attempt
        logger.warn('Intel record not found or cross-org attempt', {
          userId,
          intelId,
          organizationId,
        });
        return { canView: false, reason: 'Intel not found' };
      }

      // PUBLIC: anyone can view
      const visibility =
        ((intel as Record<string, unknown>).visibilityLevel as IntelVisibilityLevel | undefined) ||
        IntelVisibilityLevel.ORG;
      if (visibility === IntelVisibilityLevel.PUBLIC) {
        return { canView: true, visibilityLevel: visibility };
      }

      // Get user role in organization
      const userRole = await this.getUserRoleInOrganization(userId, organizationId);

      // ORG-level: members and above
      if (visibility === IntelVisibilityLevel.ORG) {
        const canView =
          userRole === UserRoleInOrg.ADMIN ||
          userRole === UserRoleInOrg.OFFICER ||
          userRole === UserRoleInOrg.MEMBER;

        if (canView) {
          return { canView: true, visibilityLevel: visibility };
        } else {
          return { canView: false, reason: 'Insufficient role for ORG-level intel' };
        }
      }

      // PRIVATE: creator or admin only
      if (visibility === IntelVisibilityLevel.PRIVATE) {
        const isCreator = (intel as Record<string, unknown>).createdBy === userId;
        const isAdmin = userRole === UserRoleInOrg.ADMIN;

        if (isCreator || isAdmin) {
          return { canView: true, visibilityLevel: visibility };
        } else {
          return { canView: false, reason: 'PRIVATE intel accessible to creator and admin only' };
        }
      }

      // Fallback: deny
      return { canView: false, reason: 'Unknown visibility level' };
    } catch (error: unknown) {
      logger.error('Error checking Intel visibility', {
        userId,
        intelId,
        organizationId,
        error,
      });
      throw error;
    }
  }

  /**
   * Get Intel entries filtered by visibility
   */
  async getVisibleIntelEntries(
    organizationId: string,
    userId: string,
    filters?: {
      limit?: number;
      offset?: number;
      search?: string;
    }
  ): Promise<{ entries: IntelEntry[]; total: number }> {
    try {
      const userRole = await this.getUserRoleInOrganization(userId, organizationId);

      let query = this.intelRepo
        .createQueryBuilder('intel')
        .where('intel.organizationId = :orgId', { orgId: organizationId });

      // Build visibility condition based on user role
      let visibilityConditions = `intel.visibilityLevel = :public`;
      const params: Record<string, string> = { public: IntelVisibilityLevel.PUBLIC };

      // Members and above can see ORG-level
      if (
        userRole === UserRoleInOrg.MEMBER ||
        userRole === UserRoleInOrg.OFFICER ||
        userRole === UserRoleInOrg.ADMIN
      ) {
        visibilityConditions += ` OR intel.visibilityLevel = :org`;
        params.org = IntelVisibilityLevel.ORG;
      }

      // Admins can see all; others can see their own PRIVATE
      if (userRole === UserRoleInOrg.ADMIN) {
        visibilityConditions += ` OR intel.visibilityLevel = :private`;
        params.private = IntelVisibilityLevel.PRIVATE;
      } else {
        visibilityConditions += ` OR (intel.visibilityLevel = :private AND intel.createdBy = :userId)`;
        params.private = IntelVisibilityLevel.PRIVATE;
        params.userId = userId;
      }

      query = query.andWhere(`(${visibilityConditions})`);

      // Apply parameters
      Object.entries(params).forEach(([key, value]) => {
        query = query.setParameter(key, value);
      });

      // Search filter (if provided)
      if (filters?.search) {
        query = query.andWhere(`(intel.title ILIKE :search OR intel.content ILIKE :search)`, {
          search: `%${filters.search}%`,
        });
      }

      // Ordering
      query = query.orderBy('intel.createdAt', 'DESC');

      // Pagination
      if (filters?.limit) {
        query = query.limit(filters.limit);
      }
      if (filters?.offset) {
        query = query.offset(filters.offset);
      }

      const [entries, total] = await query.getManyAndCount();

      // Audit log: batch access
      intelAuditLogger.log({
        action: IntelAuditAction.INTEL_LIST_ACCESSED,
        userId,
        organizationId,
        details: { count: entries.length, total },
        severity: 'info',
        performedById: userId,
      });

      return { entries, total };
    } catch (error: unknown) {
      logger.error('Error fetching visible intel entries', {
        organizationId,
        userId,
        error,
      });
      throw error;
    }
  }

  /**
   * Get single Intel entry with visibility check
   */
  async getIntelDetails(
    intelId: string,
    organizationId: string,
    userId: string
  ): Promise<IntelEntry> {
    const canView = await this.canViewIntel(userId, intelId, organizationId);

    if (!canView.canView) {
      // Log denied access
      intelAuditLogger.log({
        action: IntelAuditAction.INTEL_ACCESS_DENIED,
        userId,
        organizationId,
        resourceId: intelId,
        details: { reason: canView.reason },
        severity: 'warning',
        performedById: userId,
      });

      throw new ForbiddenError(`You do not have permission to view this intel: ${canView.reason}`);
    }

    const intel = await this.intelRepo.findOne({
      where: { id: intelId, organizationId },
    });

    if (!intel) {
      throw new NotFoundError('Intel record not found');
    }

    // Log successful access
    intelAuditLogger.log({
      action: IntelAuditAction.INTEL_ACCESSED,
      userId,
      organizationId,
      resourceId: intelId,
      details: { visibility: canView.visibilityLevel },
      severity: 'info',
      performedById: userId,
    });

    return intel;
  }

  /**
   * Update Intel visibility level (admin only)
   */
  async updateIntelVisibility(
    intelId: string,
    organizationId: string,
    userId: string,
    newVisibility: IntelVisibilityLevel
  ): Promise<IntelEntry> {
    // Check admin role
    const userRole = await this.getUserRoleInOrganization(userId, organizationId);
    if (userRole !== UserRoleInOrg.ADMIN) {
      throw new ForbiddenError('Only admins can update intel visibility');
    }

    const intel = await this.intelRepo.findOne({
      where: { id: intelId, organizationId },
    });

    if (!intel) {
      throw new NotFoundError('Intel record not found');
    }

    const oldVisibility =
      ((intel as Record<string, unknown>).visibilityLevel as IntelVisibilityLevel | undefined) ||
      IntelVisibilityLevel.ORG;
    (intel as Record<string, unknown>).visibilityLevel = newVisibility;

    const updated = await this.intelRepo.save(intel);

    // Log visibility change
    intelAuditLogger.log({
      action: IntelAuditAction.INTEL_VISIBILITY_CHANGED,
      userId,
      organizationId,
      resourceId: intelId,
      details: { oldVisibility, newVisibility },
      severity: 'warning',
      performedById: userId,
    });

    return updated;
  }
}

// Export singleton instance
export const intelVisibilityService = IntelVisibilityService.getInstance();
